  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      config: getNextAccount(),
      poolTreasury: getNextAccount(),
      treasuryAuthority: getNextAccount(),
      ownerStableAccount: getNextAccount(),
      stableMint: getNextAccount(),
      owner: getNextAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getWithdrawRecoveredInstructionDataDecoder().decode(instruction.data),
  };
